from dataclasses import dataclass
from typing import Optional
import re

@dataclass
class SemanticVersion:
    major: int
    minor: int
    patch: int
    prerelease: Optional[str] = None

    @classmethod
    def parse(cls, version_str: str) -> 'SemanticVersion':
        """
        Parse a version string like '1.2.3' or '1.2.3-beta.1'
        """
        pattern = r'^(\d+)\.(\d+)\.(\d+)(?:-([a-zA-Z0-9.]+))?$'
        match = re.match(pattern, version_str)
        if not match:
            raise ValueError(f"Invalid version string: {version_str}")

        major, minor, patch, prerelease = match.groups()
        return cls(
            major=int(major),
            minor=int(minor),
            patch=int(patch),
            prerelease=prerelease
        )

    def __str__(self) -> str:
        """
        Convert to string representation.
        """
        base = f"{self.major}.{self.minor}.{self.patch}"
        if self.prerelease:
            return f"{base}-{self.prerelease}"
        return base

    def __lt__(self, other: 'SemanticVersion') -> bool:
        """
        Compare versions for sorting.
        """
        # Compare major, minor, patch
        if (self.major, self.minor, self.patch) != (other.major, other.minor, other.patch):
            return (self.major, self.minor, self.patch) < (other.major, other.minor, other.patch)

        # Prerelease versions are less than release versions
        if self.prerelease and not other.prerelease:
            return True
        if not self.prerelease and other.prerelease:
            return False
        if self.prerelease and other.prerelease:
            return self.prerelease < other.prerelease
        return False

    def bump_major(self) -> 'SemanticVersion':
        """
        Return new version with major bumped, minor/patch reset.
        """
        return SemanticVersion(self.major + 1, 0, 0)

    def bump_minor(self) -> 'SemanticVersion':
        """
        Return new version with minor bumped, patch reset.
        """
        return SemanticVersion(self.major, self.minor + 1, 0)

    def bump_patch(self) -> 'SemanticVersion':
        """
        Return new version with patch bumped.
        """
        return SemanticVersion(self.major, self.minor, self.patch + 1)

    def is_compatible_with(self, other: 'SemanticVersion') -> bool:
        """
        Check if this version is compatible with other (same major).
        """
        return self.major == other.major
